mapper.select:
SELECT MSL_REASON, MSL_REG_DATE
FROM MEMBER_STATUS_LOG
WHERE MSL_MBR_ID = #{mbrId} 
  AND MSL_TARGET_STATUS = #{targetStatus}
ORDER BY MSL_REG_DATE DESC
LIMIT 1

mapper.update:
UPDATE MEMBER
SET MBR_USE_YN = #{mbrUseYn}
WHERE MBR_ID = #{mbrId}

mapper.select:
SELECT *,
(SELECT MSL_REASON FROM MEMBER_STATUS_LOG WHERE MSL_MBR_ID = MEMBER.MBR_ID AND MSL_TARGET_STATUS = 'N' ORDER BY MSL_REG_DATE DESC LIMIT 1) AS suspendReason FROM MEMBER WHERE 1=1
ORDER BY MBR_JOIN_DATE DESC LIMIT #{offset}, #{size}

mapper.update:
/* 회원 탈퇴 (소프트 삭제 및 마스킹) - 매개변수가 3개인 관리자용 */
UPDATE MEMBER
SET MBR_USE_YN = 'N',
    /* 🚀 탈퇴자 이메일 재가입 불가 및 UQ 충돌 방지 마스킹 */
    MBR_EMAIL = #{maskedEmail},
    /* 🚀 닉네임 UQ 충돌 방지 마스킹 */
    MBR_NICKNAME = #{maskedNickname},
    /* 🚀 리프레시 토큰 무효화 */
    MBR_REFRESH_TOKEN = NULL
WHERE MBR_ID = #{mbrId}

mapper.select:
/* 관리자: 전체 회원 목록 조회 */
SELECT 
      MBR_ID, MBR_PASSWORD, MBR_NAME, MBR_NICKNAME, MBR_EMAIL, 
      MBR_TELNO, MBR_ZIP, MBR_ADDR, MBR_DADDR, MBR_PROFILE_FILE_NO, MBR_PROVIDER_CD, 
      MBR_REFRESH_TOKEN, MBR_AUTH_CD, MBR_JOIN_DATE, MBR_LAST_LGN_DATE, MBR_USE_YN
FROM MEMBER;

mapper.update:
	/* 비밀번호 변경 */
    UPDATE MEMBER
    SET MBR_PASSWORD = #{newPassword} 
    WHERE MBR_ID = #{mbrId}

mapper.select:
	/* 이메일 중복 조회 */
    SELECT COUNT(*) 
    FROM MEMBER 
    WHERE MBR_EMAIL = #{email} 
      AND MBR_USE_YN = 'Y'

mapper.update:
	/* 회원 정보 수정 */
    UPDATE MEMBER
    SET MBR_NAME = #{mbrName},
        MBR_NICKNAME = #{mbrNickname},
        MBR_TELNO = #{mbrTelno},
        MBR_ZIP = #{mbrZip},
        MBR_ADDR = #{mbrAddr},
        MBR_DADDR = #{mbrDaddr}
    WHERE MBR_ID = #{mbrId}

mapper.select:
	/* 닉네임 중복 조회 */
    SELECT COUNT(*) 
    FROM MEMBER 
    WHERE MBR_NICKNAME = #{nickname} 
      AND MBR_USE_YN = 'Y'

mapper.insert:
INSERT INTO MEMBER (
      MBR_PASSWORD, MBR_NAME, MBR_NICKNAME, MBR_EMAIL, MBR_TELNO, 
      MBR_ZIP, MBR_ADDR, MBR_DADDR, MBR_PROVIDER_CD, MBR_AUTH_CD, 
      MBR_USE_YN
) VALUES (
      #{mbrPassword}, #{mbrName}, #{mbrNickname}, #{mbrEmail}, #{mbrTelno}, 
      #{mbrZip}, #{mbrAddr}, #{mbrDaddr}, #{mbrProviderCd}, #{mbrAuthCd}, 
      #{mbrUseYn}
)

mapper.update:
UPDATE MEMBER
SET MBR_PROFILE_FILE_NO = #{fileNo}
WHERE MBR_ID = #{mbrId}

UPDATE MEMBER
SET MBR_PROFILE_BG_FILE_NO = #{fileNo}
WHERE MBR_ID = #{mbrId}

/* 리프레시토큰 수정 */
UPDATE MEMBER
SET MBR_REFRESH_TOKEN = #{refreshToken}
WHERE MBR_ID = #{mbrId};

/* 마지막 로그인 일시 업데이트 */
UPDATE MEMBER
SET MBR_LAST_LGN_DATE = NOW()
WHERE MBR_ID = #{mbrId};
